from typing import List

def remove_duplicates(numbers: List[int]) -> List[int]:
    # तत्वों की घटनाओं की गणना करें
    counts = {}
    for num in numbers:
        if num in counts:
            counts[num] += 1
        else:
            counts[num] = 1

    # केवल उन तत्वों को शामिल करें जो एक बार घटित हुए हैं
    result = [num for num in numbers if counts[num] == 1]

    return result
